import xml.etree.ElementTree as ET

def parse_xml_config(xml_file_path):
    tree = ET.parse(xml_file_path, ET.XMLParser(no_network_access=True))
    root = tree.getroot()
    
    config_dict = {}
    for elem in root:
        if elem.tag not in config_dict:
            config_dict[elem.tag] = []
        config_dict[elem.tag].append(elem.text)
        
    return config_dict